/**
 * Power Pages Portal Web API — Vehicle Data Fetcher
 *
 * Uses the portal's built-in `webapi.safeAjax` to fetch all vehicle records
 * with pagination. Each record's raw and formatted (@OData.Community.Display.V1.FormattedValue)
 * fields are extracted and returned as `RawVehicleRecord` objects.
 */

import { API_BASE, MAX_PAGE_SIZE, VEHICLE_FIELDS } from '@data/dataverseConfig';
import { safeFetch } from '@lib/webapi';
import type { RawVehicleRecord } from '@data/dataverseDataSource';

/**
 * The $select field list matching the portal Web API reference exactly.
 */
const VEHICLE_SELECT = [
  'vpi_vehicledataid',
  'vpi_avgprice',
  'vpi_bodytype',
  'vpi_category',
  'vpi_cylinders',
  'vpi_description',
  'vpi_doors',
  'vpi_drivetype',
  'vpi_enginesize',
  'vpi_horsepower',
  'vpi_id',
  'vpi_make',
  'vpi_makecode',
  'vpi_maxprice',
  'vpi_minprice',
  'vpi_model',
  'vpi_modelcode',
  'vpi_name',
  'vpi_powertraintype',
  'vpi_pricespreadpct',
  'vpi_seats',
  'vpi_spec',
  'vpi_transmissiontronic',
  'vpi_vehicletype',
  'vpi_year',
  'vpi_yearcode',
].join(',');

/**
 * Extract a typed field from a result record, preferring the formatted value
 * annotation for choice/option-set fields.
 */
function getField<T>(result: Record<string, unknown>, field: string): T | undefined {
  return result[field] as T | undefined;
}

function getFormatted(result: Record<string, unknown>, field: string): string | undefined {
  return result[`${field}@OData.Community.Display.V1.FormattedValue`] as string | undefined;
}

interface ODataResponse {
  value: Record<string, unknown>[];
  '@odata.nextLink'?: string;   // server-driven paging token
  '@odata.count'?: number;      // total record count (if requested)
}

/**
 * Parse a raw API response record into a `RawVehicleRecord`, extracting
 * all 27 fields with formatted values for choice fields.
 */
function parseRawRecord(result: Record<string, unknown>): RawVehicleRecord {
  return {
    [VEHICLE_FIELDS.ID]: result['vpi_vehicledataid'] as string,
    [VEHICLE_FIELDS.NAME]: result['vpi_name'] as string | undefined,
    [VEHICLE_FIELDS.BUSINESS_ID]: result['vpi_id'] as string | undefined,
    [VEHICLE_FIELDS.MAKE]: getField<string>(result, 'vpi_make'),
    [VEHICLE_FIELDS.MAKE_CODE]: getField<string>(result, 'vpi_makecode'),
    [VEHICLE_FIELDS.MODEL]: getField<string>(result, 'vpi_model'),
    [VEHICLE_FIELDS.MODEL_CODE]: getField<string>(result, 'vpi_modelcode'),
    [VEHICLE_FIELDS.SPEC]: getField<string>(result, 'vpi_spec'),
    [VEHICLE_FIELDS.YEAR]: getField<string>(result, 'vpi_year'),
    [VEHICLE_FIELDS.YEAR_CODE]: getField<string>(result, 'vpi_yearcode'),
    [VEHICLE_FIELDS.DESCRIPTION]: getField<string>(result, 'vpi_description'),
    [VEHICLE_FIELDS.ENGINE_SIZE]: getField<number>(result, 'vpi_enginesize'),
    [VEHICLE_FIELDS.HORSEPOWER]: getField<number>(result, 'vpi_horsepower'),
    [VEHICLE_FIELDS.CYLINDERS]: getField<number>(result, 'vpi_cylinders'),
    [VEHICLE_FIELDS.MIN_PRICE]: getField<number>(result, 'vpi_minprice'),
    [VEHICLE_FIELDS.AVG_PRICE]: getField<number>(result, 'vpi_avgprice'),
    [VEHICLE_FIELDS.MAX_PRICE]: getField<number>(result, 'vpi_maxprice'),
    [VEHICLE_FIELDS.PRICE_SPREAD_PCT]: getField<number>(result, 'vpi_pricespreadpct'),
    [VEHICLE_FIELDS.BODY_TYPE]: getField<number>(result, 'vpi_bodytype'),
    [VEHICLE_FIELDS.BODY_TYPE + '_formatted']: getFormatted(result, 'vpi_bodytype'),
    [VEHICLE_FIELDS.CATEGORY]: getField<number>(result, 'vpi_category'),
    [VEHICLE_FIELDS.CATEGORY + '_formatted']: getFormatted(result, 'vpi_category'),
    [VEHICLE_FIELDS.TRANSMISSION]: getField<number>(result, 'vpi_transmissiontronic'),
    [VEHICLE_FIELDS.TRANSMISSION + '_formatted']: getFormatted(result, 'vpi_transmissiontronic'),
    [VEHICLE_FIELDS.DOORS]: getField<number>(result, 'vpi_doors'),
    [VEHICLE_FIELDS.DOORS + '_formatted']: getFormatted(result, 'vpi_doors'),
    [VEHICLE_FIELDS.SEATS]: getField<number>(result, 'vpi_seats'),
    [VEHICLE_FIELDS.SEATS + '_formatted']: getFormatted(result, 'vpi_seats'),
    [VEHICLE_FIELDS.DRIVE_TYPE]: getField<number>(result, 'vpi_drivetype'),
    [VEHICLE_FIELDS.DRIVE_TYPE + '_formatted']: getFormatted(result, 'vpi_drivetype'),
    [VEHICLE_FIELDS.POWERTRAIN_TYPE]: getField<number>(result, 'vpi_powertraintype'),
    [VEHICLE_FIELDS.POWERTRAIN_TYPE + '_formatted']: getFormatted(result, 'vpi_powertraintype'),
    [VEHICLE_FIELDS.VEHICLE_TYPE]: getField<number>(result, 'vpi_vehicletype'),
    [VEHICLE_FIELDS.VEHICLE_TYPE + '_formatted']: getFormatted(result, 'vpi_vehicletype'),
  };
}

/**
 * Custom Power Pages Ajax endpoint that returns ALL vehicle data server-side,
 * bypassing the 14,631-record cap of the portal `/_api/` proxy.
 *
 * The endpoint is defined as a web template named `Ajax/Vehicles-Proxy`
 * and is available at `/_services/portal/ajax.ashx?custom=Ajax/Vehicles-Proxy`.
 *
 * It uses server-side `fetchxml` to query Dataverse directly without the
 * portal proxy's record limit.
 */
const PROXY_URL = '/_services/portal/ajax.ashx?custom=Ajax/Vehicles-Proxy';

async function fetchAllVehiclesFromProxy(): Promise<RawVehicleRecord[] | null> {
  try {
    const resp = await fetch(PROXY_URL);
    if (!resp.ok) {
      console.warn(`[Vehicles-Proxy] HTTP ${resp.status} — falling back`);
      return null;
    }
    const json = await resp.json();
    const records = json?.value;
    if (!Array.isArray(records) || records.length === 0) {
      console.warn('[Vehicles-Proxy] Empty response — falling back');
      return null;
    }
    const parsed = records.map(parseRawRecord);
    console.log(`[Vehicles-Proxy] Fetched ${parsed.length} records`);
    return parsed;
  } catch (err) {
    console.warn('[Vehicles-Proxy] Failed:', err);
    return null;
  }
}

/**
 * Fallback: fetch via the portal `/_api/` using year-by-year queries.
 * Each individual year is well under the ~14K cap, so the portal API returns
 * all records for that year. The per-year results are then merged.
 */
async function fetchAllVehiclesFallback(): Promise<RawVehicleRecord[]> {
  const sampleUrl = `${API_BASE}/vpi_vehicledatas` +
    `?$select=vpi_year` +
    `&$top=1&$orderby=vpi_year asc`;
  const sampleResp = await safeFetch<ODataResponse>({ url: sampleUrl })
    .catch(() => null);
  const sampleRecord = sampleResp?.value?.[0];
  const minYear = sampleRecord ? Number(sampleRecord['vpi_year']) || 2000 : 2000;

  const years: number[] = [];
  for (let y = minYear; y <= 2026; y++) years.push(y);
  console.log(`[fetchAllVehicles] Fallback: fetching ${years.length} years (${minYear}-2026)`);

  const BATCH_SIZE = 5;
  const all: RawVehicleRecord[] = [];

  for (let i = 0; i < years.length; i += BATCH_SIZE) {
    const batch = years.slice(i, i + BATCH_SIZE);
    const results = await Promise.all(
      batch.map(year =>
        safeFetch<ODataResponse>({
          url: `${API_BASE}/vpi_vehicledatas` +
            `?$select=${VEHICLE_SELECT}` +
            `&$filter=vpi_year eq '${year}'` +
            `&$top=${MAX_PAGE_SIZE}`,
          headers: { Prefer: 'odata.include-annotations=*' },
        })
        .then(res => (res.value ?? []).map(parseRawRecord))
        .catch(() => {
          console.warn(`[fetchAllVehicles] Year ${year} returned no data`);
          return [] as RawVehicleRecord[];
        }),
      ),
    );

    all.push(...results.flat());
    console.log(`[fetchAllVehicles] Years ${batch[0]}-${batch[batch.length - 1]}: ${all.length} records so far`);
  }

  console.log(`[fetchAllVehicles] Fallback done — fetched ${all.length} records`);
  return all;
}

/**
 * Fetch ALL vehicle records from Dataverse.
 *
 * Strategy:
 *  1. Try the custom server-side proxy endpoint (Ajax/Vehicles-Proxy) first.
 *     This runs a `fetchxml` query server-side and has NO record cap.
 *  2. If the proxy is unavailable, fall back to year-by-year queries
 *     through the portal's `/_api/` (each year is under the 14K cap).
 */
export async function fetchAllVehicles(): Promise<RawVehicleRecord[]> {
  const proxyRecords = await fetchAllVehiclesFromProxy();
  if (proxyRecords) return proxyRecords;

  console.log('[fetchAllVehicles] Proxy unavailable — using fallback');
  return fetchAllVehiclesFallback();
}
